from typing import List

class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        def kmp(s, p):
            m, n = len(s), len(p)
            fail = [0] * n
            j = 0
            for i in range(1, n):
                while j > 0 and p[i] != p[j]:
                    j = fail[j - 1]
                if p[i] == p[j]:
                    j += 1
                fail[i] = j
            j = 0
            res = []
            for i in range(m):
                while j > 0 and s[i] != p[j]:
                    j = fail[j - 1]
                if s[i] == p[j]:
                    j += 1
                if j == n:
                    res.append(i - n + 1)
                    j = fail[j - 1]
            return res

        a_indices = kmp(s, a)
        b_indices = kmp(s, b)

        beautiful_indices = []
        for i in a_indices:
            if any(abs(i - j) <= k for j in b_indices):
                beautiful_indices.append(i)

        return beautiful_indices
